CODE_EXAMPLE:
public class CircuitBreaker {
  private int failureThreshold = 5;
  private int failureCount = 0;

  public void Call() {
    if (failureCount >= failureThreshold) {
      throw new Exception("Circuit breaker is open");
    }
    try {
      // Call service
    } catch {
      failureCount++;
    }
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Call_DoesNotThrow_WhenBelowThreshold() {
  var breaker = new CircuitBreaker();
  // Should not throw
  breaker.Call();
}

[TestMethod]
[ExpectedException(typeof(Exception))]
public void Call_ThrowsException_WhenAboveThreshold() {
  var breaker = new CircuitBreaker();
  for (int i = 0; i < 6; i++) breaker.Call();
}
